<?php
namespace Tests\Feature;use App\Domain\WorldMaps\WorldMapAdminService;use App\Models\World;use App\Models\WorldMap;use Database\Seeders\WorldCatalogSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\Storage;use InvalidArgumentException;use Tests\TestCase;
class WorldMapActionValidationTest extends TestCase{use RefreshDatabase;private $map;private $world;protected function setUp():void{parent::setUp();$this->seed(WorldCatalogSeeder::class);Storage::fake('public');Storage::disk('public')->put('map.png','x');$this->world=World::first();$this->map=WorldMap::create(['world_id'=>$this->world->id,'code'=>'action_map','name'=>'Action map','image_disk'=>'public','image_path'=>'map.png','original_width'=>1,'original_height'=>1,'mime_type'=>'image/png','file_size'=>1,'version'=>1,'status'=>'active','is_default'=>false,'sort_order'=>0]);}private function data($type,$extra=[]){return array_merge(['code'=>'action_'.uniqid(),'name'=>'Action','description'=>$type==='info'?'Plain info':null,'polygon_points'=>['coordinate_system'=>'normalized','points'=>[['x'=>0,'y'=>0],['x'=>0.5,'y'=>0],['x'=>0,'y'=>0.5]]],'action_type'=>$type,'display_mode'=>'panel','z_index'=>0,'status'=>'active','sort_order'=>0],$extra);}public function test_required_and_incompatible_targets_are_rejected(){foreach([$this->data('zone'),$this->data('info',['zone_id'=>1])] as $data){try{app(WorldMapAdminService::class)->saveArea($this->map,$data);$this->fail();}catch(InvalidArgumentException $e){$this->assertTrue(true);}}}public function test_internal_route_rejects_unlisted_and_authoritative_character_parameter(){foreach([$this->data('internal_route',['internal_route_name'=>'not_allowed']),$this->data('internal_route',['internal_route_name'=>'profile','internal_route_parameters'=>['character'=>999]])] as $data){try{app(WorldMapAdminService::class)->saveArea($this->map,$data);$this->fail();}catch(InvalidArgumentException $e){$this->assertStringContainsString('route',$e->getMessage());}}}public function test_active_world_action_requires_resolvable_default(){try{app(WorldMapAdminService::class)->saveArea($this->map,$this->data('world',['target_world_id'=>$this->world->id]));$this->fail();}catch(InvalidArgumentException $e){$this->assertStringContainsString('default map',$e->getMessage());}}}
